TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- Caso INSERT
    IF INSERTING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_PROFESIONALES_ASIGNADOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_PROFESIONALES_ASIGNADOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_PROFESIONALES_ASIGNADOS (
            ENVIO_BQ, ID, ID_ENTIDAD, ID_PROFESIONAL, ESTADO,
            FECHA_INICIO, FECHA_FINAL, FECHA_CREACION
        )
        VALUES (
            0, -- ENVIO_BQ para INSERT
            :NEW.ID, :NEW.ID_ENTIDAD, :NEW.ID_PROFESIONAL, :NEW.ESTADO,
            :NEW.FECHA_INICIO, :NEW.FECHA_FINAL, :NEW.FECHA_CREACION
        );
    END IF;

    -- Caso UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_PROFESIONALES_ASIGNADOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_PROFESIONALES_ASIGNADOS (
                ENVIO_BQ, ID, ID_ENTIDAD, ID_PROFESIONAL, ESTADO,
                FECHA_INICIO, FECHA_FINAL, FECHA_CREACION
            )
            VALUES (
                2, -- ENVIO_BQ para INSERT
                :NEW.ID, :NEW.ID_ENTIDAD, :NEW.ID_PROFESIONAL, :NEW.ESTADO,
                :NEW.FECHA_INICIO, :NEW.FECHA_FINAL, :NEW.FECHA_CREACION
            );       

       ELSE


            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;    

            UPDATE TKRBQ_PROFESIONALES_ASIGNADOS
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                ID_ENTIDAD = :NEW.ID_ENTIDAD,
                ID_PROFESIONAL = :NEW.ID_PROFESIONAL,
                ESTADO = :NEW.ESTADO,
                FECHA_INICIO = :NEW.FECHA_INICIO,
                FECHA_FINAL = :NEW.FECHA_FINAL,
                FECHA_CREACION = :NEW.FECHA_CREACION
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
        END IF;
    END IF;

    -- Caso DELETE
    IF DELETING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_PROFESIONALES_ASIGNADOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_PROFESIONALES_ASIGNADOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;            

        INSERT INTO TKRBQ_PROFESIONALES_ASIGNADOS (
            ENVIO_BQ, ID, ID_ENTIDAD, ID_PROFESIONAL, ESTADO,
            FECHA_INICIO, FECHA_FINAL, FECHA_CREACION
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID, :OLD.ID_ENTIDAD, :OLD.ID_PROFESIONAL, :OLD.ESTADO,
            :OLD.FECHA_INICIO, :OLD.FECHA_FINAL, :OLD.FECHA_CREACION
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_PROFESIONALES_ASIGNADOS';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);

END;
